function today(offset=0){const d=new Date();d.setDate(d.getDate()+offset);return localDate(d)}
function weekKey(s){const d=parseDateOnly(String(s).slice(0,10));if(!d)return '0000-00-00';const day=(d.getDay()+6)%7;d.setDate(d.getDate()-day);return localDate(d)}
