function renderTrend(weeks,wkNow){const el=document.querySelector('#trendCard'),totals=new Map();for(const [k,w] of weeks){const wk=k.slice(-10);if(wk==='0000-00-00')continue;totals.set(wk,(totals.get(wk)||0)+w.credited+w.bonus+w.bounty)}const logged=[...totals.keys()].sort();if(logged.length<2){el.classList.add('hide');return}const last=logged[logged.length-1]>wkNow?logged[logged.length-1]:wkNow,all=[],d=parseDateOnly(logged[0]),end=parseDateOnly(last);while(d<=end){all.push(localDate(d));d.setDate(d.getDate()+7)}const view=all.slice(-12),max=Math.max(1,...view.map(k=>totals.get(k)||0));el.classList.remove('hide');document.querySelector('#trendChart').innerHTML=view.map(k=>{const v=totals.get(k)||0,lab=parseDateOnly(k).toLocaleDateString('en-US',{month:'short',day:'numeric'});return `<div class="cbar${k===wkNow?' now':''}" title="Week of ${lab} — ${v} pts"><b>${v}</b><div class="track"><i style="height:${v?Math.max(3,Math.round(v/max*100)):0}%"></i></div><small>${lab}</small></div>`}).join('')}
