function benchmarkComparison(items=benchmarks){const latest={};items.forEach(x=>{if(!x||!['baseline','final'].includes(x.phase)||!Array.isArray(x.grades)||x.grades.length!==5)return;const key=String(x.name).toLowerCase()+'|'+x.phase;if(!latest[key]||String(x.createdAt)>String(latest[key].createdAt))latest[key]=x});return [...new Set(config.crew.concat(items.map(x=>x&&x.name)).filter(Boolean))].map(name=>{const baseline=latest[name.toLowerCase()+'|baseline'],final=latest[name.toLowerCase()+'|final'];if(!baseline||!final)return{name,baseline,final,valid:false};const compatible=String(baseline.gym).trim().toLowerCase()===String(final.gym).trim().toLowerCase()&&String(baseline.gradeScale).trim().toLowerCase()===String(final.gradeScale).trim().toLowerCase(),mean=x=>x.grades.reduce((s,n)=>s+Number(n),0)/5;return{name,baseline,final,valid:compatible,improvement:compatible?mean(final)-mean(baseline):null,floorGain:compatible?Math.min(...final.grades)-Math.min(...baseline.grades):null}})}
function renderBenchmarks(){const el=document.querySelector('#benchmarkGrid'),rows=benchmarkComparison(),complete=rows.filter(x=>x.valid),best=complete.length?complete.slice().sort((a,b)=>b.improvement-a.improvement||b.floorGain-a.floorGain)[0]:null;el.innerHTML=rows.map(x=>{const winner=best&&x.valid&&x.improvement===best.improvement&&x.floorGain===best.floorGain,detail=x.valid?`${x.improvement>=0?'+':''}${x.improvement.toFixed(1)} mean grade steps · floor ${x.floorGain>=0?'+':''}${x.floorGain}`:x.baseline&&!x.final?'Final check-in pending':x.final&&!x.baseline?'Baseline missing':x.baseline&&x.final?'Gym or scale mismatch':'No check-in yet';return `<article class="card benchmark-card"><span class="label">${winner?'Most improved · ':''}${esc(x.name)}</span><strong>${esc(detail)}</strong><small>${x.baseline?`Baseline: ${x.baseline.grades.join(', ')}`:'Record Week 1 baseline'}${x.final?` · Final: ${x.final.grades.join(', ')}`:''}</small></article>`}).join('')||'<div class="notice">No benchmark check-ins yet. Record five Week 1 sends to establish a personal baseline.</div>'}
function esc(s=''){return String(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function rememberModalTrigger(){lastModalTrigger=document.activeElement instanceof HTMLElement?document.activeElement:null}
function openLog(){rememberModalTrigger();const date=document.querySelector('#activityDate'),now=challengeToday();date.min=config.startDate;date.max=config.tripDate;date.value=now<config.startDate?config.startDate:now>config.tripDate?config.tripDate:now;const m=document.querySelector('#member');if(!m.value&&me)m.value=config.crew.find(y=>y.toLowerCase()===me.trim().toLowerCase())||me;document.querySelector('#logModal').classList.add('open');(m.value?document.querySelector('#activityType'):m).focus()}
function openBenchmark(){if(endpoint&&!benchmarkCapable)return toast('Update and redeploy the Apps Script before recording benchmarks.');rememberModalTrigger();const member=document.querySelector('#benchmarkMember');member.value=config.crew.find(x=>x.toLowerCase()===me.trim().toLowerCase())||me;document.querySelector('#benchmarkModal').classList.add('open');(member.value?document.querySelector('#benchmarkPhase'):member).focus()}
function openBounty(id){const bounty=dailyBounties(challengeToday()).find(x=>x.id===id);if(!bounty)return toast('That bounty is no longer available today.');if(endpoint&&!bountyCapable)return toast('Update and redeploy the Apps Script before claiming bounties.');rememberModalTrigger();document.querySelector('#bountyId').value=bounty.id;document.querySelector('#bountyClaimSummary').innerHTML=`<strong>${esc(bounty.title)}</strong><br>${esc(bounty.description)}<br><span class="bounty-points">+${bounty.points} point${bounty.points===1?'':'s'} above the cap</span>`;const member=document.querySelector('#bountyMember');member.value=config.crew.find(x=>x.toLowerCase()===me.trim().toLowerCase())||me;document.querySelector('#bountyNote').value='';document.querySelector('#bountyModal').classList.add('open');(member.value?document.querySelector('#bountyNote'):member).focus()}
function localBountyClaim(name,bountyId,note){const date=challengeToday(),member=config.crew.find(x=>x.toLowerCase()===name.toLowerCase())||name;if((centralConfig||config.crew.length)&&!config.crew.some(x=>x.toLowerCase()===name.toLowerCase()))throw Error(config.crew.length?'Choose a name from the crew list.':'The organizer needs to add participants.');if(!note||note.length>120)throw Error('Describe how you completed the bounty.');const bounty=dailyBounties(date).find(x=>x.id===bountyId);if(!bounty)throw Error('That bounty is no longer available today.');const credits=computeCredits(logs),qualifying=logs.some((x,i)=>x.type==='climb'&&x.date===date&&String(x.name).toLowerCase()===member.toLowerCase()&&(credits.info.get(ckey(x,i))?.credit||0)>0);if(!qualifying)throw Error('Log a credited climbing session for today first.');const mine=logs.filter(x=>x.type==='bounty'&&String(x.name).toLowerCase()===member.toLowerCase());if(mine.some(x=>x.date===date))throw Error('Only one bounty can count per day.');if(mine.filter(x=>weekKey(x.date)===weekKey(date)).length>=BOUNTY_WEEK_LIMIT)throw Error('Two bounties already count this week.');return{id:`local-bounty-${Date.now()}`,name:member,type:'bounty',points:bounty.points,date,note,createdAt:new Date().toISOString(),bountyId:bounty.id,bountyTitle:bounty.title}}
function setFieldError(id,message){const input=document.querySelector('#'+id),error=document.querySelector('#'+id+'Error');input.setAttribute('aria-invalid',String(Boolean(message)));if(error){error.textContent=message||'';error.classList.toggle('hide',!message)}}
function showConfigErrors(errors=configErrors){const box=document.querySelector('#setupErrors'),entries=Object.entries(errors);box.classList.toggle('hide',!entries.length);box.innerHTML=entries.length?`<strong>Settings need attention:</strong><br>${entries.map(([field,message])=>`${esc(field)}: ${esc(message)}`).join('<br>')}`:'';for(const [id,field] of [['challengeStart','challengeStart'],['tripDate','tripDate'],['groupGoal','groupGoal'],['crewNames','crew']])setFieldError(id,errors[field]||'')}
function clearSetupErrors(){setFieldError('endpoint','');showConfigErrors({})}
function populateSetup(){if(setupDirty)return;document.querySelector('#endpoint').value=endpoint;document.querySelector('#challengeStart').value=config.startDate;document.querySelector('#tripDate').value=config.tripDate;document.querySelector('#groupGoal').value=config.goal;document.querySelector('#crewNames').value=config.crew.join(', ');showConfigErrors()}
function openSetup(){rememberModalTrigger();setupDirty=false;clearSetupErrors();populateSetup();document.querySelector('#setupModal').classList.add('open');document.querySelector('#endpoint').focus();if(endpoint)loadRemote(false).then(ok=>{if(ok&&!setupDirty)populateSetup()})}
function closeModal(id){document.querySelector('#'+id).classList.remove('open');if(lastModalTrigger?.isConnected)lastModalTrigger.focus();lastModalTrigger=null}
function toast(s){const t=document.querySelector('#toast');t.textContent=s;t.classList.add('show');setTimeout(()=>t.classList.remove('show'),2200)}
function setDiagnostic(title,detail,bad=false,errorCode=''){const box=document.querySelector('#syncDiagnostics'),code=document.querySelector('#diagnosticCode');document.querySelector('#diagnosticTitle').textContent=title;document.querySelector('#diagnosticDetail').textContent=detail;box.classList.toggle('bad',bad);code.textContent=errorCode?`Error code: ${errorCode} · copy`:'';code.dataset.code=errorCode;code.classList.toggle('hide',!errorCode)}
function syncFailureCode(error){return error?.message==='version'?'RTS-REFRESH-VERSION':error?.message==='json'?'RTS-REFRESH-RESPONSE':error?.message==='http'?'RTS-REFRESH-HTTP':'RTS-REFRESH-NETWORK'}
function renderSync(){const el=document.querySelector('#syncStatus');if(!endpoint){el.classList.add('hide');setDiagnostic('Local demo mode','Demo entries are stored only in this browser and never merged into shared data.');return}el.className=`sync ${syncState}`;el.classList.remove('hide');const age=lastSyncedAt?Math.floor((Date.now()-lastSyncedAt)/60000):null,when=age===null?'never':age<1?'just now':`${age}m ago`,lastSuccess=lastSyncedAt?new Date(lastSyncedAt).toLocaleString():'never',protocol=protocolVersion?`v${protocolVersion}`:'not confirmed',meta=`Protocol ${protocol} · Last successful sync: ${lastSuccess}.`,settings=Object.values(configErrors);if(syncState==='loading'){el.textContent='⏳ Loading shared data…';setDiagnostic('Connecting to shared settings',`${meta} Waiting for the Sheet to respond.`)}else if(syncState==='live'){el.textContent=`● Live · synced ${when} · ↻ refresh`;setDiagnostic('Shared settings active',`${meta} Goal ${config.goal} points · trip ${config.tripDate} · ${config.crew.length} ${config.crew.length===1?'participant':'participants'}.`)}else if(syncState==='stale'){el.textContent=`⚠ Stale · last good sync ${when} · select to retry${syncDetail?' · '+syncDetail:''}`;setDiagnostic(settings.length?'Sheet settings need attention':'Using cached shared data',`${meta} ${settings.length?settings.join(' '):'Select refresh to retry.'}`,true,syncErrorCode)}else{el.textContent=`✕ Sync error · select to retry${syncDetail?' · '+syncDetail:''}`;setDiagnostic('Shared Sheet unavailable',`${meta} No fresh response is available${syncDetail?`: ${syncDetail}`:'.'} Check the deployment and select refresh to retry.`,true,syncErrorCode)}}
function unpackRemote(result){if(Array.isArray(result))return{version:0,features:[],activities:sanitizeActivities(result),benchmarks:[],config:null,configErrors:{api:'This Apps Script is outdated; redeploy the current version.'},legacy:true,serverDate:'',timeZone:''};if(!result||!Array.isArray(result.activities))throw Error('json');const version=Number(result.version);if(!SUPPORTED_API_VERSIONS.has(version))throw Error('version');return{version,features:Array.isArray(result.features)?result.features.map(String):[],activities:sanitizeActivities(result.activities),benchmarks:sanitizeActivities(result.benchmarks),config:result.config??null,configErrors:result.configErrors||{},legacy:false,serverDate:String(result.serverDate||''),timeZone:String(result.timeZone||'')}}
