function parseRemoteConfig(next,reported){const errors=backendErrors(reported);if(!next||typeof next!=='object'||Array.isArray(next)){errors.settings??='Challenge settings are missing.';return{value:null,errors}}const start=String(next.startDate||'').trim(),trip=String(next.tripDate||'').trim(),goal=typeof next.goal==='number'?next.goal:Number(String(next.goal||'').trim()),crew=uniqueCrew(next.crew);if(!parseDateOnly(start))errors.challengeStart??='Use a real date in YYYY-MM-DD format.';if(!parseDateOnly(trip))errors.tripDate??='Use a real date in YYYY-MM-DD format.';if(parseDateOnly(start)&&parseDateOnly(trip)&&start>trip)errors.challengeStart??='Start must be on or before the trip date.';if(!Number.isFinite(goal)||!Number.isInteger(goal)||goal<50||goal>10000)errors.groupGoal??='Use a whole number from 50 to 10,000.';if(!Array.isArray(next.crew))errors.crew??='Participants must come from the Participants tab.';if(crew.some(x=>x.length>30))errors.crew??='Each participant name must be 30 characters or fewer.';return{value:Object.keys(errors).length?null:{startDate:start,tripDate:trip,goal,crew},errors}}
